    28→    background: rgba(30, 41, 59, 0.5);
    29→    backdrop-filter: blur(12px);
    30→    -webkit-backdrop-filter: blur(12px);
    31→    border: 1px solid rgba(51, 65, 85, 0.5);
    32→    border-radius: 12px;
    33→  }
    34→
    35→  /* Carte avec effet hover */
