    38→  }
    39→
    40→  .card-hover:hover {
    41→    background: rgba(30, 41, 59, 0.7);
    42→    border-color: rgba(59, 130, 246, 0.3);
    43→    box-shadow: 0 10px 40px rgba(0, 0, 0, 0.2);
    44→  }
    45→
    46→  /* Badge de grade AEO */
