    53→    @apply bg-accent hover:bg-accent-hover text-white font-medium px-6 py-2.5 rounded-xl
    54→           transition-all duration-200 shadow-lg shadow-accent/20
    55→           hover:shadow-xl hover:shadow-accent/30;
    56→  }
    57→
    58→  /* Bouton secondaire */
