    67→           text-slate-50 placeholder:text-slate-500
    68→           focus:outline-none focus:border-accent/50 focus:ring-2 focus:ring-accent/20
    69→           transition-all duration-200;
    70→  }
    71→}
    72→
    73→@layer utilities {
    74→  /* Scrollbar personnalisée */
