    76→    width: 6px;
    77→  }
    78→
    79→  .custom-scrollbar::-webkit-scrollbar-track {
    80→    background: transparent;
    81→  }
    82→
    83→  .custom-scrollbar::-webkit-scrollbar-thumb {
    84→    background: rgba(148, 163, 184, 0.2);
    85→    border-radius: 3px;
    86→  }
    87→
    88→  .custom-scrollbar::-webkit-scrollbar-thumb:hover {
    89→    background: rgba(148, 163, 184, 0.4);
    90→  }
    91→
    92→  /* Masquer la scrollbar tout en gardant le scroll */
